const t=!0,richTypes={Date:t,RegExp:t,String:t,Number:t};export default function diff(t,e,o=[]){let p=[];for(const c in t)if(c in e)if(t[c]&&e[c]&&"object"==typeof t[c]&&"object"==typeof e[c]&&!richTypes[Object.getPrototypeOf(t[c]).constructor.name]&&!o.includes(t[c])){const n=diff(t[c],e[c],o.concat(t[c]));p.push(...n.map(t=>(t.path.unshift(c),t)))}else t[c]===e[c]||"object"==typeof t[c]&&"object"==typeof e[c]&&(isNaN(t[c])?t[c]+""==e[c]+"":+t[c]==+e[c])||p.push({path:[c],type:"CHANGE",value:e[c]});else p.push({type:"REMOVE",path:[c]});for(const f in e)f in t||p.push({type:"CREATE",path:[f],value:e[f]});return p}